 28→    /// <summary>
 29→    /// Kusto-backed Service Tree node lookup.
 30→    /// </summary>
 31→    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
 32→    {
 33→        private readonly ServiceTreeKustoOptions kustoOptions;
 34→        private readonly ServiceTreeClientOptions authOptions;
 35→        private readonly ILogger<ServiceTreeKustoClient> logger;
 36→        private readonly TokenCredential? tokenCredential;
 37→        private readonly string tokenScope;
 38→        private readonly bool isConfigured;
 39→        private readonly int maxBatchSize;
 40→        private readonly int maxConcurrency = 4;
 41→
 42→        /// <summary>
 43→        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
 44→        /// </summary>
 45→        /// <param name="kustoOptions">Kusto options.</param>
 46→        /// <param name="authOptions">Auth options.</param>
 47→        /// <param name="logger">Logger instance.</param>
 48→        /// <param name="credentialFactory">Optional credential factory for cross-tenant support.</param>
 49→        public ServiceTreeKustoClient(
 50→            ServiceTreeKustoOptions kustoOptions,
 51→            ServiceTreeClientOptions authOptions,
 52→            ILogger<ServiceTreeKustoClient> logger,
 53→            ICredentialFactory credentialFactory = null)
 54→        {
 55→            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
 56→            this.authOptions = authOptions ?? throw new ArgumentNullException(nameof(authOptions));
 57→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 58→
 59→            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
 60→                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
 61→            {
 62→                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
 63→                this.isConfigured = false;
 64→                return;
 65→            }
 66→
 67→            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
 68→            if (string.IsNullOrWhiteSpace(this.tokenScope))
 69→            {
 70→                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
 71→                this.isConfigured = false;
 72→                return;
 73→            }
 74→
 75→            this.tokenCredential = this.ResolveTokenCredential(credentialFactory, this.authOptions);
 76→            if (this.tokenCredential == null)
 77→            {
 78→                this.logger.LogWarning("ServiceTreeKustoClient: No AAD credentials configured for Kusto.");
 79→                this.isConfigured = false;
 80→                return;
 81→            }
 82→
 83→            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
 84→            this.isConfigured = true;
 85→
 86→            this.logger.LogInformation(
 87→                "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
 88→                this.kustoOptions.ClusterUri,
 89→                this.kustoOptions.Database,
 90→                this.kustoOptions.HierarchyTableName,
 91→                this.tokenCredential.GetType().Name,
 92→                this.tokenScope);
 93→        }
 94→
 95→        /// <inheritdoc/>
 96→        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
 97→            IEnumerable<string> serviceIds,
 98→            CancellationToken cancellationToken)
 99→        {
100→            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
101→            if (!this.isConfigured)
102→            {
103→                return results;
104→            }
105→
106→            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
107→                .Where(id => !string.IsNullOrWhiteSpace(id))
108→                .Select(id => id.Trim())
109→                .Distinct(StringComparer.OrdinalIgnoreCase)
110→                .ToList();
111→
112→            if (uniqueIds.Count == 0)
113→            {
114→                return results;
115→            }
116→
117→            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
118→            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
119→            var tasks = batches.Select(async batch =>
120→            {
121→                await semaphore.WaitAsync(cancellationToken);
122→                try
123→                {
124→                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
125→                    foreach (var pair in batchResults)
126→                    {
127→                        results[pair.Key] = pair.Value;
128→                    }
129→                }
130→                finally
131→                {
132→                    semaphore.Release();
133→                }
134→            }).ToList();
135→
136→            await Task.WhenAll(tasks);
137→            return results;
138→        }
139→
140→        private static string EscapeKustoString(string value)
141→        {
142→            return value.Replace("'", "''", StringComparison.Ordinal);
143→        }
144→
145→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
146→            IReadOnlyList<string> batch,
147→            CancellationToken cancellationToken)
148→        {
149→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
150→            if (batch.Count == 0)
151→            {
152→                return results;
153→            }
154→
155→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
156→            // cross-key results by whichever hierarchy column matched each row.
157→            var batchSet = new HashSet<string>(
158→                batch.Select(id => id.ToLowerInvariant()),
159→                StringComparer.OrdinalIgnoreCase);
160→
161→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
162→            var builder = new StringBuilder();
163→            builder.AppendLine("let ids = datatable(TargetId:string)[");
164→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
165→            builder.AppendLine("];");
166→            builder.AppendLine($"{hierarchyTable}");
167→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
168→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
169→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
170→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
171→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
172→            builder.AppendLine("| project");
173→            builder.AppendLine("    Id = tostring(ServiceId),");
174→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
175→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
176→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
177→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
178→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
179→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
180→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
181→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
182→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
183→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
184→            var query = builder.ToString();
185→
186→            var requestProperties = new ClientRequestProperties();
187→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
188→
189→            try
190→            {
191→                this.logger.LogInformation(
192→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
193→                    batch.Count,
194→                    this.kustoOptions.ClusterUri,
195→                    this.kustoOptions.Database,
196→                    this.kustoOptions.HierarchyTableName);
197→
198→                using var provider = this.CreateQueryProvider();
199→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
200→
201→                do
202→                {
203→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
204→                    if (idOrdinal < 0)
205→                    {
206→                        continue;
207→                    }
208→
209→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
210→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
211→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
212→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
213→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
214→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
215→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
216→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
217→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
218→
219→                    while (reader.Read())
220→                    {
221→                        var id = this.ReadString(reader, idOrdinal);
222→                        if (string.IsNullOrWhiteSpace(id))
223→                        {
224→                            continue;
225→                        }
226→
227→                        var node = new ServiceTreeNode
228→                        {
229→                            Id = id,
230→                            Name = this.ReadString(reader, nameOrdinal),
231→                            Level = this.ReadString(reader, levelOrdinal),
232→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
233→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
234→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
235→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
236→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
237→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
238→                        };
239→
240→                        // Always key by the native ServiceId for backward compatibility.
241→                        results[id] = node;
242→
243→                        // Also key by any hierarchy ancestor ID that the caller asked for.
244→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
245→                        // find the result via hierarchyResults.TryGetValue(inputId).
246→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
247→                        foreach (var hierarchyId in new[]
248→                        {
249→                            teamGroupId,
250→                            node.ServiceGroupId,
251→                            node.OrganizationId,
252→                            node.DivisionId,
253→                        })
254→                        {
255→                            if (!string.IsNullOrWhiteSpace(hierarchyId)
256→                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
257→                            {
258→                                results[hierarchyId] = node;
259→                            }
260→                        }
261→                    }
262→                }
263→                while (results.Count == 0 && reader.NextResult());
264→
265→                this.logger.LogInformation(
266→                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
267→                    results.Count,
268→                    batch.Count);
269→            }
270→            catch (OperationCanceledException)
271→            {
272→                throw;
273→            }
274→            catch (Exception ex)
275→            {
276→                this.logger.LogError(
277→                    ex,
278→                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
279→                    this.kustoOptions.ClusterUri,
280→                    this.kustoOptions.Database,
281→                    this.kustoOptions.HierarchyTableName,
282→                    this.tokenCredential?.GetType().Name ?? "null",
283→                    batch.Count);
284→                throw;
285→            }
286→
287→            return results;
288→        }
289→
290→        private ICslQueryProvider CreateQueryProvider()
291→        {
292→            var kcsb = new KustoConnectionStringBuilder(this.kustoOptions.ClusterUri, this.kustoOptions.Database)
293→                .WithAadAzureTokenCredentialsAuthentication(this.tokenCredential!);
294→            return KustoClientFactory.CreateCslQueryProvider(kcsb);
295→        }
296→
297→        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
298→        {
299→            for (int i = 0; i < ids.Count; i += batchSize)
300→            {
301→                var count = Math.Min(batchSize, ids.Count - i);
302→                var batch = new List<string>(count);
303→                for (int j = 0; j < count; j++)
304→                {
305→                    batch.Add(ids[i + j]);
306→                }
307→
308→                yield return batch;
309→            }
310→        }
311→
312→        private string ResolveTokenScope(ServiceTreeKustoOptions options)
313→        {
314→            if (!string.IsNullOrWhiteSpace(options.TokenScope))
315→            {
316→                return options.TokenScope;
317→            }
318→
319→            if (Uri.TryCreate(options.ClusterUri, UriKind.Absolute, out var uri))
320→            {
321→                return $"{uri.GetLeftPart(UriPartial.Authority)}/.default";
322→            }
323→
324→            return string.Empty;
325→        }
326→
327→        private TokenCredential? ResolveTokenCredential(
328→            ICredentialFactory? credentialFactory,
329→            ServiceTreeClientOptions options)
330→        {
331→            // When ICredentialFactory is available AND auth mode is DefaultAzureCredential,
332→            // use the factory for cross-tenant support (PME MSI → MSFT tenant token).
333→            if (credentialFactory != null
334→                && options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
335→            {
336→                try
337→                {
338→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
339→                    this.logger.LogInformation(
340→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
341→                        cred.GetType().Name);
342→                    return cred;
343→                }
344→                catch (Exception ex)
345→                {
346→                    this.logger.LogError(
347→                        ex,
348→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
349→                    throw;
350→                }
351→            }
352→
353→            return this.CreateTokenCredential(options);
354→        }
355→
356→        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
357→        {
358→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
359→            {
360→                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
361→                {
362→                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
363→                });
364→            }
365→
366→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
367→            {
368→                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
369→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
370→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
371→                {
372→                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
373→                }
374→
375→                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
376→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
377→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
378→                {
379→#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
380→                    var cert = this.LoadAadCertificate(options);
381→#pragma warning restore CA2000
382→
383→                    return new ClientCertificateCredential(
384→                        options.AadTenantId,
385→                        options.AadClientId,
386→                        cert,
387→                        new ClientCertificateCredentialOptions { SendCertificateChain = true });
388→                }
389→
390→                if (!string.IsNullOrWhiteSpace(options.AadClientId))
391→                {
392→                    return new ManagedIdentityCredential(options.AadClientId);
393→                }
394→
395→                return new ManagedIdentityCredential();
396→            }
397→
398→            return null;
399→        }
400→
401→        private string NormalizeIdentifier(string value)
402→        {
403→            if (string.IsNullOrWhiteSpace(value))
404→            {
405→                return value;
406→            }
407→
408→            var trimmed = value.Trim();
409→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
410→                ? trimmed
411→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
412→        }
413→
414→        private int TryGetOrdinal(IDataReader reader, string name)
415→        {
416→            try
417→            {
418→                return reader.GetOrdinal(name);
419→            }
420→            catch (IndexOutOfRangeException)
421→            {
422→                return -1;
423→            }
424→        }
425→
426→        private string ReadString(IDataReader reader, int ordinal)
427→        {
428→            if (ordinal < 0 || reader.IsDBNull(ordinal))
429→            {
430→                return string.Empty;
431→            }
432→
433→            var value = reader.GetValue(ordinal);
434→            return value?.ToString() ?? string.Empty;
435→        }
436→
437→        private X509Certificate2 LoadAadCertificate(ServiceTreeClientOptions options)
438→        {
439→            try
440→            {
441→                var raw = Convert.FromBase64String(options.AadClientCertificateBase64);
442→                return new X509Certificate2(raw, options.AadClientCertificatePassword, X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet);
443→            }
444→            catch (FormatException ex)
445→            {
446→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
447→                throw;
448→            }
449→            catch (CryptographicException ex)
450→            {
451→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
452→                throw;
453→            }
454→        }
455→    }
456→
457→#pragma warning restore CA1303
458→}
