165→            builder.AppendLine("];");
166→            builder.AppendLine($"{hierarchyTable}");
167→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
168→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
169→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
170→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
171→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
172→            builder.AppendLine("| project");
173→            builder.AppendLine("    Id = tostring(ServiceId),");
174→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
175→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
176→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
177→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
178→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
179→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
180→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
181→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
182→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
183→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
184→            var query = builder.ToString();
