43→        /// <inheritdoc/>
44→        public async Task<IReadOnlyDictionary<string, string>> ResolveAsync(CancellationToken cancellationToken)
45→        {
46→            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
47→
48→            try
49→            {
50→                // 1. Fetch all service auth quota entries.
51→                var serviceAuthQuotas = await this.configService
52→                    .GetServiceQuotaAndAuthManagementAsync(string.Empty);
53→
54→                if (serviceAuthQuotas == null || serviceAuthQuotas.Count == 0)
55→                {
56→                    this.logger.LogWarning("AppIdToProductResolver: No service auth quotas found.");
57→                    return result;
58→                }
59→
60→                // 2. Resolve their ServiceTreeIds to parent groups.
61→                var serviceTreeIds = serviceAuthQuotas
62→                    .Select(q => q.ServiceTreeId ?? string.Empty)
63→                    .Where(id => !string.IsNullOrWhiteSpace(id))
64→                    .Distinct(StringComparer.OrdinalIgnoreCase);
65→
66→                var parentLookup = await this.parentResolver
67→                    .ResolveParentsAsync(serviceTreeIds, cancellationToken);
68→
69→                // 3. Build QuotaAppId → Product mapping.
70→                foreach (var entry in serviceAuthQuotas)
71→                {
72→                    if (string.IsNullOrEmpty(entry.QuotaAppId))
73→                    {
74→                        continue;
75→                    }
76→
77→                    if (parentLookup.TryGetValue(entry.ServiceTreeId ?? string.Empty, out var parent)
78→                        && !string.IsNullOrEmpty(parent.Product))
79→                    {
80→                        result.TryAdd(entry.QuotaAppId, parent.Product);
81→                    }
82→                }
83→
84→                this.logger.LogInformation(
85→                    "AppIdToProductResolver resolved {Count} AppId→Product mappings from {TotalCount} service auth quotas.",
86→                    result.Count,
87→                    serviceAuthQuotas.Count);
88→            }
89→            catch (Exception ex)
90→            {
91→                this.logger.LogError(ex, "AppIdToProductResolver failed to resolve AppId→Product mappings.");
92→            }
93→
94→            return result;
95→        }
96→    }
