356→        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
357→        {
358→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
359→            {
360→                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
361→                {
362→                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
363→                });
364→            }
365→
366→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
367→            {
368→                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
369→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
370→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
371→                {
372→                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
373→                }
374→
375→                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
376→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
377→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
378→                {
379→#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
380→                    var cert = this.LoadAadCertificate(options);
381→#pragma warning restore CA2000
382→
383→                    return new ClientCertificateCredential(
