401→        private string NormalizeIdentifier(string value)
402→        {
403→            if (string.IsNullOrWhiteSpace(value))
404→            {
405→                return value;
406→            }
407→
408→            var trimmed = value.Trim();
409→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
410→                ? trimmed
411→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
412→        }
