347→                try
348→                {
349→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
350→                    this.logger.LogInformation(
351→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
352→                        cred.GetType().Name);
353→                    return cred;
354→                }
355→                catch (Exception ex)
356→                {
357→                    this.logger.LogError(
358→                        ex,
359→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
360→                    throw;
361→                }
362→            }
363→
364→            return this.CreateTokenCredential(options);
365→        }
366→
367→        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
368→        {
369→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
370→            {
371→                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
372→                {
373→                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
374→                });
375→            }
376→
377→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
378→            {
379→                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
380→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
381→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
382→                {
383→                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
384→                }
385→
386→                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
387→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
388→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
389→                {
390→#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
391→                    var cert = this.LoadAadCertificate(options);
392→#pragma warning restore CA2000
393→
394→                    return new ClientCertificateCredential(
395→                        options.AadTenantId,
396→                        options.AadClientId,
397→                        cert,
398→                        new ClientCertificateCredentialOptions { SendCertificateChain = true });
399→                }
400→
401→                if (!string.IsNullOrWhiteSpace(options.AadClientId))
402→                {
403→                    return new ManagedIdentityCredential(options.AadClientId);
404→                }
405→
406→                return new ManagedIdentityCredential();
407→            }
408→
409→            return null;
410→        }
411→
412→        private string NormalizeIdentifier(string value)
413→        {
414→            if (string.IsNullOrWhiteSpace(value))
415→            {
416→                return value;
417→            }
418→
419→            var trimmed = value.Trim();
420→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
421→                ? trimmed
422→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
423→        }
424→
425→        private int TryGetOrdinal(IDataReader reader, string name)
426→        {
427→            try
428→            {
429→                return reader.GetOrdinal(name);
430→            }
431→            catch (IndexOutOfRangeException)
432→            {
433→                return -1;
434→            }
435→        }
436→
437→        private string ReadString(IDataReader reader, int ordinal)
438→        {
439→            if (ordinal < 0 || reader.IsDBNull(ordinal))
440→            {
441→                return string.Empty;
442→            }
443→
444→            var value = reader.GetValue(ordinal);
445→            return value?.ToString() ?? string.Empty;
446→        }
447→
448→        private X509Certificate2 LoadAadCertificate(ServiceTreeClientOptions options)
449→        {
450→            try
451→            {
452→                var raw = Convert.FromBase64String(options.AadClientCertificateBase64);
453→                return new X509Certificate2(raw, options.AadClientCertificatePassword, X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet);
454→            }
455→            catch (FormatException ex)
456→            {
457→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
458→                throw;
459→            }
460→            catch (CryptographicException ex)
461→            {
462→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
463→                throw;
464→            }
465→        }
466→    }
467→
468→#pragma warning restore CA1303
469→}
