 7→namespace CodeXCore.ServiceTree
 8→{
 9→    using System;
10→    using System.Collections.Generic;
11→    using System.Linq;
12→    using System.Threading;
13→    using System.Threading.Tasks;
14→    using CodeXCore.Services;
15→    using Microsoft.Extensions.Logging;
16→
17→    /// <summary>
18→    /// Resolves Papyrus QuotaAppId values to their owning Product (Org) name
19→    /// by fetching service auth quotas and resolving their Service Tree parents.
20→    /// </summary>
21→    public sealed class AppIdToProductResolver : IAppIdToProductResolver
22→    {
23→        private readonly IPapyrusConfigService configService;
24→        private readonly IServiceTreeParentResolver parentResolver;
25→        private readonly ILogger<AppIdToProductResolver> logger;
26→
27→        /// <summary>
28→        /// Initializes a new instance of the <see cref="AppIdToProductResolver"/> class.
29→        /// </summary>
30→        /// <param name="configService">Papyrus config service for fetching service auth quotas.</param>
31→        /// <param name="parentResolver">Service Tree parent resolver.</param>
32→        /// <param name="logger">Logger.</param>
33→        public AppIdToProductResolver(
34→            IPapyrusConfigService configService,
35→            IServiceTreeParentResolver parentResolver,
36→            ILogger<AppIdToProductResolver> logger)
37→        {
38→            this.configService = configService ?? throw new ArgumentNullException(nameof(configService));
39→            this.parentResolver = parentResolver ?? throw new ArgumentNullException(nameof(parentResolver));
40→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
41→        }
42→
43→        /// <inheritdoc/>
44→        public async Task<IReadOnlyDictionary<string, string>> ResolveAsync(CancellationToken cancellationToken)
45→        {
46→            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
47→
48→            try
49→            {
50→                // 1. Fetch all service auth quota entries.
51→                var serviceAuthQuotas = await this.configService
52→                    .GetServiceQuotaAndAuthManagementAsync(string.Empty);
53→
54→                if (serviceAuthQuotas == null || serviceAuthQuotas.Count == 0)
55→                {
56→                    this.logger.LogWarning("AppIdToProductResolver: No service auth quotas found.");
57→                    return result;
58→                }
59→
60→                // 2. Resolve their ServiceTreeIds to parent groups.
61→                var serviceTreeIds = serviceAuthQuotas
62→                    .Select(q => q.ServiceTreeId ?? string.Empty)
63→                    .Where(id => !string.IsNullOrWhiteSpace(id))
64→                    .Distinct(StringComparer.OrdinalIgnoreCase);
65→
66→                var parentLookup = await this.parentResolver
67→                    .ResolveParentsAsync(serviceTreeIds, cancellationToken);
68→
69→                // 3. Build QuotaAppId → Product mapping.
70→                foreach (var entry in serviceAuthQuotas)
71→                {
72→                    if (string.IsNullOrEmpty(entry.QuotaAppId))
73→                    {
74→                        continue;
75→                    }
76→
77→                    if (parentLookup.TryGetValue(entry.ServiceTreeId ?? string.Empty, out var parent)
78→                        && !string.IsNullOrEmpty(parent.Product))
79→                    {
80→                        result.TryAdd(entry.QuotaAppId, parent.Product);
81→                    }
82→                }
83→
84→                this.logger.LogInformation(
85→                    "AppIdToProductResolver resolved {Count} AppId→Product mappings from {TotalCount} service auth quotas.",
86→                    result.Count,
87→                    serviceAuthQuotas.Count);
88→            }
89→            catch (Exception ex)
90→            {
91→                this.logger.LogError(ex, "AppIdToProductResolver failed to resolve AppId→Product mappings.");
92→            }
93→
94→            return result;
95→        }
96→    }
97→}
