 89→        /// <summary>
 90→        /// Builds options from environment variables.
 91→        /// </summary>
 92→        /// <returns>Options resolved from environment variables.</returns>
 93→        public static ServiceTreeClientOptions FromEnvironment()
 94→        {
 95→            var options = new ServiceTreeClientOptions();
 96→
 97→            bool endpointSet = false;
 98→            string? endpoint = Environment.GetEnvironmentVariable("SERVICETREE_ENDPOINT");
 99→            if (!string.IsNullOrWhiteSpace(endpoint))
100→            {
101→                options.Endpoint = endpoint.Trim();
102→                endpointSet = true;
103→            }
104→
105→            string? authMode = Environment.GetEnvironmentVariable("SERVICETREE_AUTH_MODE");
106→            if (!string.IsNullOrWhiteSpace(authMode)
107→                && Enum.TryParse(authMode, true, out ServiceTreeAuthenticationMode parsedMode))
108→            {
109→                options.AuthenticationMode = parsedMode;
110→            }
111→
112→            string? thumbprint = Environment.GetEnvironmentVariable("SERVICETREE_CERT_THUMBPRINT");
113→            if (!string.IsNullOrWhiteSpace(thumbprint))
114→            {
115→                options.CertificateThumbprint = thumbprint.Trim();
116→            }
117→
118→            string? storeName = Environment.GetEnvironmentVariable("SERVICETREE_CERT_STORE_NAME");
119→            if (!string.IsNullOrWhiteSpace(storeName) && Enum.TryParse(storeName, true, out StoreName parsedStoreName))
120→            {
121→                options.CertificateStoreName = parsedStoreName;
122→            }
123→
124→            string? storeLocation = Environment.GetEnvironmentVariable("SERVICETREE_CERT_STORE_LOCATION");
125→            if (!string.IsNullOrWhiteSpace(storeLocation) && Enum.TryParse(storeLocation, true, out StoreLocation parsedStoreLocation))
126→            {
127→                options.CertificateStoreLocation = parsedStoreLocation;
128→            }
129→
130→            string? certBase64 = Environment.GetEnvironmentVariable("SERVICETREE_CERT_BASE64");
131→            if (!string.IsNullOrWhiteSpace(certBase64))
132→            {
133→                options.CertificateBase64 = certBase64.Trim();
134→            }
135→
136→            string? certPassword = Environment.GetEnvironmentVariable("SERVICETREE_CERT_PASSWORD");
137→            if (!string.IsNullOrWhiteSpace(certPassword))
138→            {
139→                options.CertificatePassword = certPassword;
140→            }
141→
142→            string? aadTenantId = Environment.GetEnvironmentVariable("SERVICETREE_AAD_TENANT_ID");
143→            if (!string.IsNullOrWhiteSpace(aadTenantId))
144→            {
145→                options.AadTenantId = aadTenantId.Trim();
146→            }
147→
148→            string? aadClientId = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CLIENT_ID");
149→            if (!string.IsNullOrWhiteSpace(aadClientId))
150→            {
151→                options.AadClientId = aadClientId.Trim();
152→            }
153→
154→            string? aadClientSecret = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CLIENT_SECRET");
155→            if (!string.IsNullOrWhiteSpace(aadClientSecret))
156→            {
157→                options.AadClientSecret = aadClientSecret;
158→            }
159→
160→            string? aadCertBase64 = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CERT_BASE64");
161→            if (!string.IsNullOrWhiteSpace(aadCertBase64))
162→            {
163→                options.AadClientCertificateBase64 = aadCertBase64.Trim();
164→            }
165→
166→            string? aadCertPassword = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CERT_PASSWORD");
167→            if (!string.IsNullOrWhiteSpace(aadCertPassword))
168→            {
169→                options.AadClientCertificatePassword = aadCertPassword;
170→            }
171→
172→            string? aadAudience = Environment.GetEnvironmentVariable("SERVICETREE_AAD_AUDIENCE");
173→            if (!string.IsNullOrWhiteSpace(aadAudience))
174→            {
175→                options.AadAudience = aadAudience.Trim();
176→            }
177→
178→            string? aadScope = Environment.GetEnvironmentVariable("SERVICETREE_AAD_SCOPE");
179→            if (!string.IsNullOrWhiteSpace(aadScope))
180→            {
181→                options.AadScope = aadScope.Trim();
182→            }
183→
184→            if (!endpointSet && (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad
185→                || options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential))
186→            {
187→                options.Endpoint = DefaultAadEndpoint;
188→            }
189→
190→            return options;
191→        }
192→    }
